print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]}')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} ({u[1]}) | {u[2]} | {u[3]}')
